local _M = {}

-- Simple XML parser that handles entity references
-- Works within OpenResty environment

local entity_map = {
    ["&lt;"] = "<",
    ["&gt;"] = ">",
    ["&amp;"] = "&",
    ["&quot;"] = '"',
    ["&apos;"] = "'",
}

local function decode_entities(str)
    if not str then return str end
    str = str:gsub("&#x(%x+);", function(hex)
        return string.char(tonumber(hex, 16))
    end)
    str = str:gsub("&#(%d+);", function(dec)
        return string.char(tonumber(dec))
    end)
    for entity, char in pairs(entity_map) do
        str = str:gsub(entity, char)
    end
    return str
end

local function strip_namespace(tag)
    if not tag then return tag end
    local stripped = tag:match("^[^:]+:(.+)$")
    return stripped or tag
end

local function parse_attributes(attr_str)
    local attrs = {}
    if not attr_str or attr_str == "" then
        return attrs
    end
    for name, value in attr_str:gmatch('([%w_:%-]+)%s*=%s*"([^"]*)"') do
        attrs[name] = decode_entities(value)
    end
    for name, value in attr_str:gmatch("([%w_:%-]+)%s*=%s*'([^']*)'") do
        attrs[name] = decode_entities(value)
    end
    return attrs
end

local function parse_xml(xml_str)
    if not xml_str or xml_str == "" then
        return nil, "empty XML input"
    end

    -- Remove XML declaration
    xml_str = xml_str:gsub("<%?xml[^%?]*%?>", "")
    -- Remove comments
    xml_str = xml_str:gsub("<!%-%-.-%--%>", "")
    -- Remove CDATA and extract content
    xml_str = xml_str:gsub("<!%[CDATA%[(.-)%]%]>", "%1")

    local stack = {}
    local root = { _children = {}, _type = "root" }
    local current = root

    table.insert(stack, current)

    local pos = 1
    while pos <= #xml_str do
        local text_start, tag_start = xml_str:find("<", pos)

        if not text_start then
            -- Remaining text
            local remaining = xml_str:sub(pos):match("^%s*(.-)%s*$")
            if remaining and remaining ~= "" then
                current._text = (current._text or "") .. decode_entities(remaining)
            end
            break
        end

        -- Handle text between tags
        if text_start > pos then
            local text = xml_str:sub(pos, text_start - 1)
            local trimmed = text:match("^%s*(.-)%s*$")
            if trimmed and trimmed ~= "" then
                current._text = (current._text or "") .. decode_entities(trimmed)
            end
        end

        -- Determine tag type
        local tag_end = xml_str:find(">", tag_start)
        if not tag_end then
            return nil, "malformed XML: unclosed tag at position " .. tostring(tag_start)
        end

        local tag_content = xml_str:sub(tag_start + 1, tag_end - 1)

        if tag_content:sub(1, 1) == "/" then
            -- Closing tag
            local tag_name = tag_content:sub(2):match("^%s*(%S+)%s*$")
            tag_name = strip_namespace(tag_name)

            if current._name ~= tag_name then
                return nil, "mismatched closing tag: expected </" .. tostring(current._name) .. "> but found </" .. tag_name .. ">"
            end

            table.remove(stack)
            current = stack[#stack]

        elseif tag_content:sub(-1) == "/" then
            -- Self-closing tag
            local content = tag_content:sub(1, -2)
            local tag_name = content:match("^(%S+)")
            local attr_str = content:match("^%S+%s+(.+)$")

            local node = {
                _name = strip_namespace(tag_name),
                _full_name = tag_name,
                _attrs = parse_attributes(attr_str),
                _children = {},
                _type = "element",
            }

            table.insert(current._children, node)

            local name = node._name
            if current[name] then
                if type(current[name]) ~= "table" or current[name]._type then
                    current[name] = { current[name] }
                end
                table.insert(current[name], node)
            else
                current[name] = node
            end
        else
            -- Opening tag
            local tag_name = tag_content:match("^(%S+)")
            local attr_str = tag_content:match("^%S+%s+(.+)$")

            local node = {
                _name = strip_namespace(tag_name),
                _full_name = tag_name,
                _attrs = parse_attributes(attr_str),
                _children = {},
                _type = "element",
            }

            table.insert(current._children, node)

            local name = node._name
            if current[name] then
                if type(current[name]) ~= "table" or current[name]._type then
                    current[name] = { current[name] }
                end
                table.insert(current[name], node)
            else
                current[name] = node
            end

            table.insert(stack, node)
            current = node
        end

        pos = tag_end + 1
    end

    if #stack > 1 then
        return nil, "malformed XML: unclosed tags remain"
    end

    return root
end

-- Find a node by path (e.g., "Envelope.Body.GetUser")
local function find_node(root, path)
    local current = root
    for segment in path:gmatch("[^%.]+") do
        if not current then return nil end
        current = current[segment]
    end
    return current
end

-- Extract all leaf text values into a flat table
local function extract_values(node, result, prefix)
    result = result or {}
    prefix = prefix or ""

    if not node then return result end

    if node._text then
        local key = prefix ~= "" and prefix or node._name
        result[key] = node._text
    end

    if node._children then
        for _, child in ipairs(node._children) do
            local child_prefix
            if prefix ~= "" then
                child_prefix = prefix .. "." .. child._name
            else
                child_prefix = child._name
            end
            extract_values(child, result, child_prefix)
        end
    end

    return result
end

-- Extract SOAP action from headers
local function get_soap_action(headers)
    local soap_action = headers["SOAPAction"] or headers["soapaction"]
    if soap_action then
        soap_action = soap_action:gsub('^"', ''):gsub('"$', '')
        return soap_action
    end

    local content_type = headers["Content-Type"] or headers["content-type"] or ""
    local action = content_type:match('action="([^"]+)"')
    return action
end

-- Detect SOAP version from content type or XML namespace
local function detect_soap_version(headers, xml_doc)
    local content_type = headers["Content-Type"] or headers["content-type"] or ""

    if content_type:find("application/soap%+xml") then
        return "1.2"
    elseif content_type:find("text/xml") then
        return "1.1"
    end

    -- Try to detect from namespace in the document
    if xml_doc and xml_doc._children then
        for _, child in ipairs(xml_doc._children) do
            local full = child._full_name or ""
            local attrs = child._attrs or {}
            for attr_name, attr_val in pairs(attrs) do
                if attr_val:find("schemas%.xmlsoap%.org/soap/envelope") then
                    return "1.1"
                elseif attr_val:find("www%.w3%.org/2003/05/soap%-envelope") then
                    return "1.2"
                end
            end
        end
    end

    return "1.1"
end

-- Build a SOAP fault response
local function build_soap_fault(fault_code, fault_string, detail, soap_version)
    soap_version = soap_version or "1.1"

    if soap_version == "1.2" then
        return string.format([[<?xml version="1.0" encoding="UTF-8"?>
<soap:Envelope xmlns:soap="http://www.w3.org/2003/05/soap-envelope">
  <soap:Body>
    <soap:Fault>
      <soap:Code>
        <soap:Value>soap:%s</soap:Value>
      </soap:Code>
      <soap:Reason>
        <soap:Text xml:lang="en">%s</soap:Text>
      </soap:Reason>
      <soap:Detail>%s</soap:Detail>
    </soap:Fault>
  </soap:Body>
</soap:Envelope>]], fault_code, fault_string, detail or "")
    else
        return string.format([[<?xml version="1.0" encoding="UTF-8"?>
<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
  <soap:Body>
    <soap:Fault>
      <faultcode>soap:%s</faultcode>
      <faultstring>%s</faultstring>
      <detail>%s</detail>
    </soap:Fault>
  </soap:Body>
</soap:Envelope>]], fault_code, fault_string, detail or "")
    end
end

-- Main request handler for OpenResty
function _M.handle_request()
    ngx.req.read_body()
    local body = ngx.req.get_body_data()

    if not body then
        local body_file = ngx.req.get_body_file()
        if body_file then
            local f = io.open(body_file, "r")
            if f then
                body = f:read("*a")
                f:close()
            end
        end
    end

    if not body or body == "" then
        ngx.status = 400
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(build_soap_fault("Client", "Empty request body"))
        return ngx.exit(400)
    end

    local xml_doc, err = parse_xml(body)
    if not xml_doc then
        ngx.status = 400
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(build_soap_fault("Client", "XML parsing error: " .. tostring(err)))
        return ngx.exit(400)
    end

    local headers = ngx.req.get_headers()
    local soap_version = detect_soap_version(headers, xml_doc)
    local soap_action = get_soap_action(headers)

    -- Navigate SOAP structure
    local envelope = find_node(xml_doc, "Envelope")
    if not envelope then
        ngx.status = 400
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(build_soap_fault("Client", "Missing SOAP Envelope element", nil, soap_version))
        return ngx.exit(400)
    end

    local soap_header = find_node(envelope, "Header")
    local soap_body = find_node(envelope, "Body")

    if not soap_body then
        ngx.status = 400
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(build_soap_fault("Client", "Missing SOAP Body element", nil, soap_version))
        return ngx.exit(400)
    end

    -- Extract operation from Body's first child
    local operation = nil
    local operation_params = {}

    if soap_body._children and #soap_body._children > 0 then
        local op_node = soap_body._children[1]
        operation = op_node._name
        operation_params = extract_values(op_node)
    end

    -- If no SOAPAction header, try to derive from operation
    if not soap_action and operation then
        soap_action = operation
    end

    -- Extract SOAP header values for auth, routing, etc.
    local header_values = {}
    if soap_header then
        header_values = extract_values(soap_header)
    end

    -- Build the parsed request context
    local request_context = {
        soap_version = soap_version,
        soap_action = soap_action,
        operation = operation,
        params = operation_params,
        headers = header_values,
        raw_body = body,
        xml_doc = xml_doc,
        envelope = envelope,
        soap_header = soap_header,
        soap_body = soap_body,
    }

    -- Store in ngx.ctx for downstream processing
    ngx.ctx.soap_request = request_context

    -- Log parsed request information
    ngx.log(ngx.INFO, string.format(
        "SOAP Gateway: version=%s action=%s operation=%s",
        soap_version,
        tostring(soap_action),
        tostring(operation)
    ))

    return request_context
end

-- Route SOAP request to appropriate backend handler
function _M.route_request(route_table)
    local ctx = ngx.ctx.soap_request
    if not ctx then
        local parsed, err = _M.handle_request()
        if not parsed then
            return
        end
        ctx = ngx.ctx.soap_request
    end

    local handler = route_table[ctx.operation] or route_table[ctx.soap_action]

    if not handler then
        -- Try wildcard/default handler
        handler = route_table["*"]
    end

    if not handler then
        ngx.status = 500
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(build_soap_fault(
            "Server",
            "Unknown operation: " .. tostring(ctx.operation),
            nil,
            ctx.soap_version
        ))
        return ngx.exit(500)
    end

    local ok, result = pcall(handler, ctx)
    if not ok then
        ngx.log(ngx.ERR, "SOAP handler error: " .. tostring(result))
        ngx.status = 500
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(build_soap_fault(
            "Server",
            "Internal server error",
            tostring(result),
            ctx.soap_version
        ))
        return ngx.exit(500)
    end

    return result
end

-- Helper to send a SOAP response
function _M.send_response(body_content, soap_version, status_code)
    soap_version = soap_version or (ngx.ctx.soap_request and ngx.ctx.soap_request.soap_version) or "1.1"
    status_code = status_code or 200

    local ns
    if soap_version == "1.2" then
        ns = "http://www.w3.org/2003/05/soap-envelope"
        ngx.header["Content-Type"] = "application/soap+xml; charset=utf-8"
    else
        ns = "http://schemas.xmlsoap.org/soap/envelope/"
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
    end

    local response = string.format([[<?xml version="1.0" encoding="UTF-8"?>
<soap:Envelope xmlns:soap="%s">
  <soap:Body>
    %s
  </soap:Body>
</soap:Envelope>]], ns, body_content)

    ngx.status = status_code
    ngx.say(response)
    return ngx.exit(status_code)
end

